INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 1, 105, 0, 0.029, "仲間と夏を楽しむ、夏海の魔法士。自分を変えたいという固い決意で、障害物を無効化して走り続ける。", 0, 160, 1, 1.5, 101, 122601, 110, 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (3, 2, 111, 0, 0.014, "太陽よりも輝く、夏海の元気娘。　持ち前の身体能力で、どんなコースも柔軟に対応し、駆け抜ける。", 1, 120, 2, 2.5, 102, 122401, 105, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 3, 105, 1, 0.017, "波打ち際に煌めく、夏海の剣士。　日々の鍛錬で鍛えた脚で、長い距離も速度を落とさず走り切る。", 0, 350, 3, 2.5, 103, 122501, 110, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (3, 4, 105, 0, 0.016, "海の幸に目がない、渚のお姫様。　『王家の装備』の力を解放し、障害物をものともせず前へと進む。", 1, 130, 4, 1.5, 104, 107501, 110, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 5, 105, 0, 0.014, "海でも主さまをお世話する、白浜の巫女。精霊の力で自身を加速させ、誰よりも速くゴールを目指す。", 0, 160, 5, 2.5, 105, 107601, 110, 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 6, 103, 1, 0.029, "水着姿を恥じらう、ツンデレ猫娘。お得意の魔法で、対戦相手の走りを妨害し、レースを有利に進める。", 0, 255, 6, 3.5, 106, 107801, 120, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 7, 103, 0, 0.013, "優雅に浜を駆ける、真夏のマホ姫。しゃなりしゃなりと、雅な身のこなしで障害物を跳び越えていく。", 0, 160, 7, 3.5, 107, 110601, 120, 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 8, 103, 1, 0.014, "浜の平和を守る、真夏の狼娘。　　獣人の強靭なスタミナで、レース　後半にスパートをかける。", 0, 350, 8, 2.5, 108, 110401, 110, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (3, 9, 100, 0, 0.012, "浜に力強く舞う、真夏の南国娘。　レースの喧噪の中でも精神を乱さず後半に大きな捲りを見せる。", 1, 130, 9, 1.5, 109, 110501, 105, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 10, 103, 0, 0.014, "浜の事件を嗅ぎ付けた、真夏の　　名探偵。高い推理力と魔法で、的確に対戦相手の走りを乱す。", 0, 200, 10, 2.5, 110, 115701, 105, 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 11, 103, 1, 0.071, "再び鎧を脱いだ、灼熱の騎士団長。実戦で培った判断力で、瞬時にバリアを展開し、障害物を無力化する。", 0, 350, 11, 2.5, 111, 113601, 105, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (3, 12, 103, 0, 0.014, "水が苦手な、海辺の気まぐれ猫娘。浜に現れた美少女義賊は、対戦相手のスピードを奪いとる。", 1, 130, 12, 1.5, 112, 107901, 120, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 13, 105, 0, 0.022, "バカンスも効率第一な、海の傭兵。レースでも最高効率を求め、どんな状況でも隙のない走りを見せる。", 0, 200, 13, 1.5, 113, 108001, 110, 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 14, 108, 0, 0.031, "真夏の太陽が良く似合う、海辺の　サレンママ。多才で器用、どんな　障害物もエレガントに越えていく。", 0, 160, 14, 2.5, 114, 110301, 110, 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 15, 105, 0, 0.036, "海に嵐を呼ぶ夏のドジっ娘メイド。日頃から災難に慣れており、多少　のトラブルには動じたりしない。", 1, 130, 15, 0.5, 115, 107701, 110, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 16, 95, 1, 0.048, "粋な夏を愉しむ、若夏の姉御。　　流麗な身体捌きで、始・継・終と、UBを重ねるごとに、加速する。", 0, 350, 16, 3.5, 116, 113101, 110, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (3, 17, 105, 0, 0.043, "夏のトキメキに触れた、オタク魔法少女。多彩な魔法を操り、少しずつ他の走者の速度を落とし続ける。", 1, 130, 17, 1.5, 117, 113301, 105, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 18, 95, 0, 0.018, "海獄に降臨せし、真夏の冥姫。　　レース後半に魔力を全解放し、　　蒼き疾風と成りて浜を駆け抜ける。", 1, 130, 18, 1.5, 118, 113201, 105, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 19, 108, 0, 0.021, "夏の夕を火花で彩る、渚の壊し屋。『壊し屋』の異名と過激な愛情は、対戦相手にプレッシャーを与える。", 0, 160, 19, 2.5, 119, 117001, 110, 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 20, 105, 1, 0.036, "青春に生きる者を導く、夏の先生。夢へと邁進する聖母の加護が、その身をあらゆる困難から守る。", 0, 255, 20, 2.5, 120, 113501, 110, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (3, 21, 105, 1, 0.02, "笑顔の応援が眩しい、夏の超能力　ガール。超能力を駆使して、どんな障害物もひとっ飛びで乗り越える。", 0, 350, 21, 2.5, 121, 113401, 105, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 22, 105, 0, 0.018, "海辺で大人の魅力を放つ、夏の　　セクシー先生。その魅力に囚われた対戦相手は、走りを乱してしまう。", 1, 130, 22, 2.5, 122, 110101, 110, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (3, 23, 111, 0, 0.03, "水着も絶対外さない、夏のカリスマモデル。走りのバイブスは超テンアゲで、スピードはおにやば。", 0, 160, 23, 3.5, 123, 110001, 105, 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 24, 103, 0, 0.027, "南の島も盛り上げる、真夏のアイドル。悪天候でも笑顔を絶やさず後半もリズムを上げて走り切る。", 1, 130, 24, 1.5, 124, 117201, 110, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 25, 108, 0, 0.02, "海原に美声を響かす、渚の歌姫。　守護の賛歌と精霊の加護により、　障害物から身を守る。", 0, 160, 25, 3.5, 125, 117301, 105, 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (3, 26, 105, 1, 0.04, "夏でも天邪鬼な、夕凪のテーラー。張り巡らされた魔法の糸で、他の走者の自由を奪う。", 0, 350, 26, 2.5, 126, 117401, 110, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 27, 105, 1, 0.009, "向日葵が良く似合う、海辺の　　　お姉ちゃん。秘密結社の一員で、　抜群の身体能力が一番の武器。", 0, 350, 27, 3.5, 127, 117101, 110, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 28, 105, 1, 0.022, "渚でおっとり、夏色うさぎっこ。　うさぎさんパワー全開で、ぴょん　ぴょんとコースを跳ね回る。", 0, 255, 28, 3.5, 128, 122901, 120, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (3, 29, 105, 0, 0.028, "無邪気さ弾ける、夏色いたずら娘。砂浜でも、いたずらの準備は万端！レースに大波乱が巻き起こる！？", 1, 130, 29, 2.5, 129, 122801, 110, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 30, 108, 0, 0.023, "海でも真面目な、夏色優等生。　　高めた魔力を解き放ち、一瞬の内に他の走者を置き去りにする。", 0, 130, 30, 3.5, 130, 122701, 105, 1);
